namespace sv_2390c75be026462bbac53fb1602896df.Client.Models;

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
}

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required List<StatusUpdate> StatusUpdates { get; init; }
}

using sv_2390c75be026462bbac53fb1602896df.Client.Models;

namespace sv_2390c75be026462bbac53fb1602896df.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_2390c75be026462bbac53fb1602896df.Client.Models;
using sv_2390c75be026462bbac53fb1602896df.Client.Services;

namespace sv_2390c75be026462bbac53fb1602896df.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 3, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 8, 0, 0, TimeSpan.Zero), Status = "Picked Up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 14, 30, 0, TimeSpan.Zero), Status = "In Transit", Location = "Philadelphia, PA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 29, 6, 15, 0, TimeSpan.Zero), Status = "In Transit", Location = "Chicago, IL" },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 9, 0, 0, TimeSpan.Zero), Status = "Picked Up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 26, 11, 0, 0, TimeSpan.Zero), Status = "In Transit", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 16, 45, 0, TimeSpan.Zero), Status = "Out for Delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 10, 20, 0, TimeSpan.Zero), Status = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 29, 1, 0, 0, TimeSpan.Zero), Status = "Processing", Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (!SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        return shipment;
    }
}

using System.Net;
using System.Net.Http.Json;
using sv_2390c75be026462bbac53fb1602896df.Client.Models;

namespace sv_2390c75be026462bbac53fb1602896df.Client.Services;

public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Received an empty response from the server.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_2390c75be026462bbac53fb1602896df.Client.Models
@using sv_2390c75be026462bbac53fb1602896df.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

@if (isLoading)
{
    <div class="shipment-loading">
        <p><em>Loading shipment details for @TrackingNumber&hellip;</em></p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="shipment-error">
        <p>@errorMessage</p>
        <button @onclick="Retry">Retry</button>
    </div>
}
else if (shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @shipment.TrackingNumber</h2>
        <p><strong>Status:</strong> @shipment.Status</p>
        <p><strong>Location:</strong> @shipment.Location</p>
        <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("f")</p>

        <h3>Status Updates</h3>
        <table>
            <thead>
                <tr>
                    <th>Timestamp</th>
                    <th>Status</th>
                    <th>Location</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Status</td>
                        <td>@update.Location</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? shipment;
    private bool isLoading;
    private string? errorMessage;

    private CancellationTokenSource? cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request before starting a new one.
        cts?.Cancel();
        cts?.Dispose();
        cts = new CancellationTokenSource();
        var ct = cts.Token;

        shipment = null;
        errorMessage = null;
        isLoading = true;

        try
        {
            shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Load was cancelled (navigation change or dispose) — do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            errorMessage = "The request timed out. Please try again.";
        }
        catch (KeyNotFoundException ex)
        {
            Logger.LogWarning(ex, "Shipment not found: {TrackingNumber}", TrackingNumber);
            errorMessage = $"Shipment '{TrackingNumber}' was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task Retry()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        cts?.Cancel();
        cts?.Dispose();
    }
}

